import React from 'react';

export default function App() {
  return (
    <main>
      <h1>Hello from the client review panel</h1>
      <p>This is a static sample file rendered in read-only mode.</p>
    </main>
  );
}

:root {
  --surface: #0f172a;
  --surface-strong: #020617;
  --accent: #38bdf8;
}

body {
  margin: 0;
  background: linear-gradient(180deg, var(--surface), var(--surface-strong));
  color: #e2e8f0;
}

.card {
  border: 1px solid rgba(148, 163, 184, 0.16);
  border-radius: 1rem;
  background: rgba(15, 23, 42, 0.7);
}

const routes = [
  '/overview',
  '/audit-log',
  '/release-notes',
];

export function bootstrapViewer() {
  return routes.map((route) => ({ route, enabled: true }));
}
